{action_set_definitions}: {
  "get_sensor_readings": {
    "description": "Retrieves real-time sensor data for a specific equipment ID on a production line. Returns suction pressure, fluid temperature, and acoustic noise levels.",
    "parameters": {
      "type": "object",
      "properties": {
        "equipment_id": {
          "type": "string",
          "description": "The unique identifier for the equipment (e.g., 'Feed_Pump_P101')."
        },
        "sensor_list": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "List of sensors to query: 'suction_pressure', 'temperature', 'discharge_pressure', 'vibration_level'."
        }
      },
      "required": [
        "equipment_id",
        "sensor_list"
      ]
    },
    "example_output": {
      "suction_pressure_bar": 2.1,
      "fluid_temp_celsius": 85.5,
      "vibration_rms": 4.2
    }
  },
  "get_pump_design_specs": {
    "description": "Retrieves technical specifications for a pump, including the Net Positive Suction Head Required (NPSHr) and design fluid properties.",
    "parameters": {
      "type": "object",
      "properties": {
        "equipment_id": {
          "type": "string",
          "description": "The equipment identifier."
        }
      },
      "required": [
        "equipment_id"
      ]
    },
    "example_output": {
      "npsh_required_m": 1.8,
      "rated_flow_m3h": 150.0,
      "fluid_type": "Water-based polymer"
    }
  },
  "calculate_npsh_margin": {
    "description": "Calculates the NPSH available (NPSHa) based on suction pressure and temperature, then returns the margin ratio (NPSHa / NPSHr).",
    "parameters": {
      "type": "object",
      "properties": {
        "suction_pressure": {
          "type": "number"
        },
        "temperature": {
          "type": "number"
        },
        "npsh_required": {
          "type": "number"
        },
        "fluid_type": {
          "type": "string"
        }
      },
      "required": [
        "suction_pressure",
        "temperature",
        "npsh_required",
        "fluid_type"
      ]
    },
    "example_output": {
      "npsh_available_m": 1.95,
      "margin_ratio": 1.08
    }
  },
  "get_maintenance_records": {
    "description": "Searches the maintenance database for recent repair events, seal replacements, or reported leaks for a specific asset.",
    "parameters": {
      "type": "object",
      "properties": {
        "equipment_id": {
          "type": "string"
        },
        "lookback_days": {
          "type": "integer"
        }
      },
      "required": [
        "equipment_id",
        "lookback_days"
      ]
    },
    "example_output": {
      "events": [
        {
          "date": "2023-10-12",
          "component": "Mechanical Seal",
          "issue": "Minor weeping noticed"
        },
        {
          "date": "2023-11-01",
          "component": "Suction Flange",
          "issue": "Gasket degradation"
        }
      ]
    }
  },
  "calculate_thermal_adjustment": {
    "description": "Determines the exact temperature reduction in Celsius required to raise the NPSH margin ratio to a specific target.",
    "parameters": {
      "type": "object",
      "properties": {
        "current_temp": {
          "type": "number"
        },
        "current_npsha": {
          "type": "number"
        },
        "npshr": {
          "type": "number"
        },
        "target_ratio": {
          "type": "number"
        }
      },
      "required": [
        "current_temp",
        "current_npsha",
        "npshr",
        "target_ratio"
      ]
    },
    "example_output": {
      "required_reduction_celsius": 12.5
    }
  },
  "submit_diagnostic_report": {
    "description": "Submits the final root cause analysis and remediation plan to the system.",
    "parameters": {
      "type": "object",
      "properties": {
        "calculated_margin": {
          "type": "number"
        },
        "failure_mode": {
          "type": "string",
          "enum": [
            "True Hydrodynamic Cavitation",
            "Pseudo-Cavitation (Air Ingress)"
          ]
        },
        "remediation_details": {
          "type": "string"
        }
      },
      "required": [
        "calculated_margin",
        "failure_mode",
        "remediation_details"
      ]
    },
    "example_output": null
  }
}
